import{c as e,Q as d,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Lifecycle Statuses","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/statuses.md","filePath":"guide/concepts/statuses.md","lastUpdated":1778912818000}'),o={name:"guide/concepts/statuses.md"};function n(s,t,i,c,l,h){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="lifecycle-statuses" tabindex="-1">Lifecycle Statuses <a class="header-anchor" href="#lifecycle-statuses" aria-label="Permalink to &quot;Lifecycle Statuses&quot;">​</a></h1><p>Every meaningful entity in the Console has a status. Statuses are not free-form — each entity has a fixed set of values and a fixed set of transitions. This page is the reference.</p><h2 id="customer" tabindex="-1">Customer <a class="header-anchor" href="#customer" aria-label="Permalink to &quot;Customer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Reachable from</th></tr></thead><tbody><tr><td><code>active</code></td><td>Normal operating state.</td><td><code>suspended</code> (via Reactivate)</td></tr><tr><td><code>suspended</code></td><td>Sign-in blocked for all of the customer&#39;s users. Reason required.</td><td><code>active</code> (via Suspend)</td></tr><tr><td><code>churned</code></td><td>The customer has left. Data retained per policy. Reason required.</td><td><code>active</code>, <code>suspended</code> (via Churn)</td></tr></tbody></table><p>A customer with active tenants cannot be deleted — you must archive the tenants first.</p><h2 id="tenant" tabindex="-1">Tenant <a class="header-anchor" href="#tenant" aria-label="Permalink to &quot;Tenant&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Reachable from</th></tr></thead><tbody><tr><td><code>provisioning</code></td><td>Being created on the target instance.</td><td>initial state</td></tr><tr><td><code>active</code></td><td>Operating normally.</td><td><code>provisioning</code>, <code>suspended</code> (via Resume)</td></tr><tr><td><code>suspended</code></td><td>Paused; users cannot sign in.</td><td><code>active</code> (via Suspend)</td></tr><tr><td><code>archived</code></td><td>Retired; data retained. Reason required.</td><td><code>active</code>, <code>suspended</code> (via Archive)</td></tr></tbody></table><p>Archived tenants can be <strong>restored</strong> back to <code>active</code>. Tenants can also be <strong>moved</strong> between customers (status unchanged) and <strong>migrated</strong> to a different instance via a migration job.</p><h2 id="instance" tabindex="-1">Instance <a class="header-anchor" href="#instance" aria-label="Permalink to &quot;Instance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Reachable from</th></tr></thead><tbody><tr><td><code>provisioning</code></td><td>Created in the Console but the agent has not reported in yet.</td><td>initial state</td></tr><tr><td><code>active</code></td><td>Heartbeat current.</td><td><code>provisioning</code></td></tr><tr><td><code>inactive</code></td><td>Heartbeat missing long enough that the Console no longer trusts state.</td><td><code>active</code></td></tr><tr><td><code>decommissioned</code></td><td>Retired permanently. Cannot be undone.</td><td>any (via Decommission)</td></tr></tbody></table><p>Instance decommissioning cannot be undone and is gated by a confirmation dialog.</p><h2 id="user" tabindex="-1">User <a class="header-anchor" href="#user" aria-label="Permalink to &quot;User&quot;">​</a></h2><p>The user lifecycle applies to both internal users and customer/portal users.</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>invited</code></td><td>Invite sent; user has not completed acceptance. The invite can be re-sent.</td></tr><tr><td><code>active</code></td><td>Signed in at least once and operational.</td></tr><tr><td><code>deactivated</code></td><td>Access revoked. Sessions are invalidated. The user cannot sign in until reactivated.</td></tr></tbody></table><h2 id="release" tabindex="-1">Release <a class="header-anchor" href="#release" aria-label="Permalink to &quot;Release&quot;">​</a></h2><p>See <a href="./releases">Releases &amp; Deployments</a> for the full state machine. Summary:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>draft</code></td><td>Created; not yet deployed.</td></tr><tr><td><code>in_progress</code></td><td>Flowing through the pipeline.</td></tr><tr><td><code>paused</code></td><td>Awaiting approval, trigger, or manual resume.</td></tr><tr><td><code>completed</code></td><td>All stages succeeded.</td></tr><tr><td><code>failed</code></td><td>A stage failed terminally.</td></tr><tr><td><code>rolled_back</code></td><td>At least one instance was rolled back.</td></tr><tr><td><code>cancelled</code></td><td>Operator cancelled the release.</td></tr><tr><td><code>archived</code></td><td>Hidden from the default view; purged after 30 days.</td></tr></tbody></table><h2 id="invoice" tabindex="-1">Invoice <a class="header-anchor" href="#invoice" aria-label="Permalink to &quot;Invoice&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>draft</code></td><td>Being prepared. Not yet sent.</td></tr><tr><td><code>issued</code></td><td>Sent to the customer.</td></tr><tr><td><code>paid</code></td><td>Fully paid.</td></tr><tr><td><code>overdue</code></td><td>Past the due date and not paid. Surfaced with red styling.</td></tr><tr><td><code>void</code></td><td>Cancelled; does not count toward customer totals.</td></tr></tbody></table><h2 id="payment" tabindex="-1">Payment <a class="header-anchor" href="#payment" aria-label="Permalink to &quot;Payment&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>pending</code></td><td>Recorded but not yet processed.</td></tr><tr><td><code>processing</code></td><td>In-flight with the payment provider.</td></tr><tr><td><code>completed</code></td><td>Funds received and reconciled.</td></tr><tr><td><code>failed</code></td><td>Processing failed.</td></tr></tbody></table><h2 id="discrepancy" tabindex="-1">Discrepancy <a class="header-anchor" href="#discrepancy" aria-label="Permalink to &quot;Discrepancy&quot;">​</a></h2><p>The <a href="./../admin/discrepancies">Discrepancies</a> inbox surfaces tenant-level dangling data. Each finding has:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>open</code></td><td>Detected in the current or a recent scan. Needs action.</td></tr><tr><td><code>resolved</code></td><td>Operator purged the dangle (or the worker auto-purged).</td></tr><tr><td><code>discarded</code></td><td>Operator dismissed from the current inbox. <strong>Not permanent</strong> — the next scan re-detects and flips back to <code>open</code>. Discard means &quot;snooze until next audit cycle.&quot;</td></tr><tr><td><code>auto_purged</code></td><td>The worker met strict age and inactivity criteria and purged without operator input.</td></tr></tbody></table><p>There are two <strong>kinds</strong> of discrepancy:</p><ul><li><strong>Ghost</strong> — a PostgreSQL row with no MongoDB data.</li><li><strong>Orphan</strong> — MongoDB data with no PostgreSQL row.</li></ul><h2 id="where-statuses-appear" tabindex="-1">Where statuses appear <a class="header-anchor" href="#where-statuses-appear" aria-label="Permalink to &quot;Where statuses appear&quot;">​</a></h2><ul><li><strong>Badges</strong> on list rows and detail headers, colour-coded by severity (green = healthy, orange = warning, red = problem, grey = retired).</li><li><strong>Banners</strong> on detail pages when an entity is in a non-operating state.</li><li><strong>Filters</strong> on every list view, defaulted to the most useful subset (usually &quot;active&quot;).</li></ul>',28)])])}const g=e(o,[["render",n]]);export{p as __pageData,g as default};
